function isObject(val) {
    return val !== null && typeof val === 'object'
}

function convertJsonToCsv(json) {
    const columnMap = buildColumnMap(json)
    const matrix = createMatrix(columnMap)
    return matrix
}

function buildColumnMap(arr) {
    const m = new Map()

    function buildColumnMapHelper(key, value) {
        if (typeof value === "string") {
            if (!m.has(key)) {
                m.set(key, [])
            }
            m.get(key).push(value)
        } else if (Array.isArray(value)) {
            for (const el of value) {
                buildColumnMapHelper(key, el)
            }
        } else if (isObject(value)) {
            for (const [nextKey, nextVal] of Object.entries(value)) {
                const newKey = !key ? nextKey : key + "." + nextKey
                buildColumnMapHelper(newKey, nextVal)
            }
        }
    }

    buildColumnMapHelper("", arr)

    return m
}

function createMatrix(m) {
    const keys = Array.from(m.keys())
    const matrix = [keys]
    let column = 0

    for (const key of keys) {
        const values = m.get(key)

        for (let i = 1; i <= values.length; i++) {
            if (!matrix[i]) {
                matrix.push(new Array(keys.length).fill(""))
            }

            matrix[i][column] = values[i - 1]
        }

        column += 1
    }

    return matrix
}

