                "]";

        try {
            List<Object> list = objectMapper.readValue(j, new TypeReference<List<Object>>(){});
            System.out.println("list element count is "+list.size());
            System.out.println(list);
            System.out.println();

            // main input is a list, inside of list are two maps
            List<String> keys = new ArrayList<>();
            List<String> vals = new ArrayList<>();
            List<String>[] arr = new ArrayList[2];
            arr[0] = keys;
            arr[1] = vals;

            for (Object o : list) {
                // lets pretend i dont know there are two maps
                // lets pretend i have two values both coming in with a root key that is an empty str for now
                arr = parseEntry(arr,"", o, "");
            }

            for (int i=0; i<arr[0].size(); i++) {
                System.out.println(arr[0].get(i)+" : "+arr[1].get(i));
            }
        }
        catch(IOException e) {
            e.printStackTrace();
        }

    }

    // takes an object key and object value pair and parses it
    public static List<String>[] parseEntry(List<String>[] arr, String k, Object v, String parentKey) {
        if (v.getClass().toString().equals("class java.lang.String")) {
            arr[0].add(parentKey+k);
            arr[1].add((String)v);
        }
        else if (v.getClass().toString().equals("class java.util.ArrayList")) {
            // inside the value (which is a List), everything is a value
            // the value itself could be a plain string, or another list, or a map, we dont know
            // we just treat it as value, so for all such values, call recursively
            for (Object e : (ArrayList<Object>)v) {
                arr = parseEntry(arr, k,e,"");
            }
        }
        else if (v.getClass().toString().equals("class java.util.LinkedHashMap")) {
            // inside the value (which is a map), everything is a bunch of key value pairs
            // foreach entry, take the key and the value and process linearly with recursion
            LinkedHashMap<String, Object> typecastedMap = (LinkedHashMap<String, Object>) v;
            for (Map.Entry<String, Object> e : typecastedMap.entrySet()) {
                arr = parseEntry(arr, e.getKey(),e.getValue(),k);
            }
        }
        return arr;
    }
}
